@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/classification/isco-08> ;
            sh:resultMessage "A DDI-CDI StatisticalClassification should be maintained by at least one cdi:isMaintainedBy Organization (or id-reference)" ;
            sh:resultPath cdi:isMaintainedBy ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI StatisticalClassification should be maintained by at least one cdi:isMaintainedBy Organization (or id-reference)" ;
                    sh:minCount 1 ;
                    sh:path cdi:isMaintainedBy ;
                    sh:severity sh:Warning ] ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/classification/isco-08> ;
            sh:resultMessage "A DDI-CDI StatisticalClassification should be defined by at least one cdi:isDefinedBy Concept (or id-reference)" ;
            sh:resultPath cdi:isDefinedBy ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A DDI-CDI StatisticalClassification should be defined by at least one cdi:isDefinedBy Concept (or id-reference)" ;
                    sh:minCount 1 ;
                    sh:path cdi:isDefinedBy ;
                    sh:severity sh:Warning ] ] .

